// src/components/FormAgendamento.jsx
import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function FormAgendamento({
  onNovoAgendamento,
  agendamentoEditando,
  onFimEdicao
}) {
  const { user } = useAuth();
  const token = user?.token;
  const role  = user?.role; // "recepcao" ou "aluno"

  // 1) Tipo de atendimento
  const [tipoAtendimento, setTipoAtendimento] = useState('Novo');

  // 2) Pacientes e pesquisa
  const [pacientes, setPacientes] = useState([]);
  const [buscaPaciente, setBuscaPaciente] = useState('');
  const [pacienteId, setPacienteId] = useState('');
  const [nomePaciente, setNomePaciente] = useState('');
  const [telefone, setTelefone] = useState('');
  const [showLista, setShowLista] = useState(false);

  // 3) Listas para selects
  const [disciplinas, setDisciplinas] = useState([]);
  const [alunos, setAlunos] = useState([]);

  // 4) Campos do formulário
  const [disciplinaId, setDisciplinaId] = useState('');
  const [data, setData] = useState('');
  const [hora, setHora] = useState('');
  const [observacoes, setObservacoes] = useState('');

  // 5) Operador (obrigatório) e auxiliares (opcionais)
  const [operadorId, setOperadorId] = useState('');
  const [auxiliar1Id, setAuxiliar1Id] = useState('');
  const [auxiliar2Id, setAuxiliar2Id] = useState('');

  // 6) Mensagem de validação/erro
  const [mensagem, setMensagem] = useState('');

  // 7) Ref para pesquisa de paciente
  const inputRef = useRef(null);

  // Carrega disciplinas, pacientes e alunos
  useEffect(() => {
    if (!token) return;

    // disciplinas
    axios
      .get('/api/disciplinas', { headers: { Authorization: `Bearer ${token}` } })
      .then(res => setDisciplinas(res.data))
      .catch(err => console.error('Erro disciplinas:', err.response?.data || err.message));

    // pacientes
    axios
      .get('/api/pacientes', { headers: { Authorization: `Bearer ${token}` } })
      .then(res => setPacientes(res.data))
      .catch(err => console.error('Erro pacientes:', err.response?.data || err.message));

    // alunos → se for recepção, pega todos; se for aluno, só o próprio
    const urlAlunos = role === 'recepcao' ? '/api/alunos' : '/api/alunos/me';
    axios
      .get(urlAlunos, { headers: { Authorization: `Bearer ${token}` } })
      .then(res => {
        const list = Array.isArray(res.data) ? res.data : [res.data];
        setAlunos(list);
      })
      .catch(err => {
        console.error('Erro ao buscar alunos:', err.response?.data || err.message);
        setMensagem('Não foi possível carregar lista de alunos.');
      });
  }, [token, role]);

  // Fecha dropdown de paciente ao clicar fora
  useEffect(() => {
    const handleClickOutside = e => {
      if (inputRef.current && !inputRef.current.contains(e.target)) {
        setShowLista(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Se veio agendamento para editar, popula campos
  useEffect(() => {
    if (!agendamentoEditando) {
      // limpa tudo
      setTipoAtendimento('Novo');
      setDisciplinaId('');
      setPacienteId('');
      setNomePaciente('');
      setTelefone('');
      setData('');
      setHora('19:00');
      setObservacoes('');
      setOperadorId('');
      setAuxiliar1Id('');
      setAuxiliar2Id('');
      setBuscaPaciente('');
      setShowLista(false);
      setMensagem('');
      return;
    }

    // preenche campos de edição
    setTipoAtendimento(
      agendamentoEditando.status === 'Solicitado'
        ? 'Solicitar'
        : agendamentoEditando.status
    );
    setDisciplinaId(String(agendamentoEditando.disciplina_id || ''));
    setPacienteId(agendamentoEditando.paciente_id || '');
    setNomePaciente(agendamentoEditando.nome_paciente || '');
    setTelefone(agendamentoEditando.telefone || '');
    setData(agendamentoEditando.data ? agendamentoEditando.data.slice(0, 10) : '');
    setHora(agendamentoEditando.hora || '19:00');
    setObservacoes(agendamentoEditando.observacoes || '');

    setOperadorId(
      agendamentoEditando.aluno_id
        ? String(agendamentoEditando.aluno_id)
        : String(agendamentoEditando.operador_id || '')
    );
    setAuxiliar1Id(String(agendamentoEditando.auxiliar1_id || ''));
    setAuxiliar2Id(String(agendamentoEditando.auxiliar2_id || ''));

    setBuscaPaciente(
      (agendamentoEditando.nome_paciente || '') +
      (agendamentoEditando.telefone ? ' - ' + agendamentoEditando.telefone : '')
    );
    setShowLista(false);
    setMensagem('');
  }, [agendamentoEditando]);

  // filtra pacientes por nome ou telefone
  const pacientesFiltrados = pacientes.filter(p => {
    const b = buscaPaciente.toLowerCase();
    return (
      p.nome.toLowerCase().includes(b) ||
      (p.telefone && p.telefone.includes(b))
    );
  });

  // usuário seleciona um paciente
  const handleSelecionarPaciente = paciente => {
    setPacienteId(paciente.id);
    setNomePaciente(paciente.nome);
    setTelefone(paciente.telefone);
    setBuscaPaciente(paciente.nome + (paciente.telefone ? ' - ' + paciente.telefone : ''));
    setShowLista(false);
  };

  // SUBMIT (POST ou PUT)
  const handleSubmit = e => {
    e.preventDefault();

    // validações básicas
    if (!disciplinaId) {
      setMensagem('Selecione uma disciplina.');
      return;
    }
    if (!operadorId) {
      setMensagem('Selecione um operador.');
      return;
    }
    if (operadorId === auxiliar1Id) {
      setMensagem('Operador e auxiliar devem ser diferentes.');
      return;
    }
    if (!pacienteId && tipoAtendimento !== 'Solicitar') {
      setMensagem('Selecione um paciente.');
      return;
    }

    // monta payload
    const dados = {
      disciplina_id: disciplinaId,
      paciente_id: tipoAtendimento === 'Solicitar' ? null : pacienteId,
      nome_paciente: tipoAtendimento === 'Solicitar' ? null : nomePaciente,
      telefone: tipoAtendimento === 'Solicitar' ? null : telefone,
      data,
      hora,
      observacoes: tipoAtendimento === 'Solicitar' ? null : observacoes,
      aluno_id: operadorId,
      auxiliar1_id: auxiliar1Id,
      auxiliar2_id: auxiliar2Id,
      status: tipoAtendimento === 'Solicitar' ? 'Solicitado' : tipoAtendimento,
      solicitado_por_recepcao: tipoAtendimento === 'Solicitar'
    };

    const config = { headers: { Authorization: `Bearer ${token}` } };

    if (agendamentoEditando) {
      axios
        .put(`/api/agendamentos/${agendamentoEditando.id}`, dados, config)
        .then(() => {
          setMensagem('Agendamento atualizado!');
          onNovoAgendamento?.();
          onFimEdicao?.();
        })
        .catch(err => {
          console.error('Erro ao atualizar:', err.response?.data || err.message);
          setMensagem('Erro ao atualizar agendamento.');
        });
    } else {
      axios
        .post('/api/agendamentos', dados, config)
        .then(() => {
          setMensagem('Agendamento cadastrado!');
          onNovoAgendamento?.();
          // limpa só os campos
          setTipoAtendimento('Novo');
          setDisciplinaId('');
          setPacienteId('');
          setNomePaciente('');
          setTelefone('');
          setData('');
          setHora('19:00');
          setObservacoes('');
          setOperadorId('');
          setAuxiliar1Id('');
          setAuxiliar2Id('');
          setBuscaPaciente('');
        })
        .catch(err => {
          console.error('Erro ao cadastrar:', err.response?.data || err.message);
          setMensagem('Erro ao cadastrar agendamento.');
        });
    }
  };

  return (
    <div className="bg-white mx-auto max-w-2xl rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">Agendar Paciente</h2>

        {/* tipo de atendimento */}
        <div className="flex flex-wrap gap-2 mb-6">
          {['Novo', 'Retorno', 'Solicitar'].map(t => (
            <button
              key={t}
              type="button"
              onClick={() => setTipoAtendimento(t)}
              className={`px-4 py-1 rounded-full font-semibold transition ${
                tipoAtendimento === t
                  ? 'bg-[#D9E0FF] text-gray-800'
                  : 'bg-gray-200 text-gray-800 hover:bg-gray-300'
              }`}
            >
              {t === 'Solicitar' ? 'Solicitar para Recepção' : t}
            </button>
          ))}
        </div>

        {/* disciplina */}
        <div className="mb-6">
          <label className="block mb-1 font-medium">Disciplina</label>
          <div className="flex flex-wrap gap-2">
            {disciplinas.map(d => (
              <button
                key={d.id}
                type="button"
                className={`px-4 py-1 rounded-full border transition ${
                  disciplinaId === String(d.id)
                    ? 'bg-[#D9E0FF] text-gray-800 font-semibold'
                    : 'bg-gray-100 text-gray-800 hover:bg-gray-300'
                }`}
                onClick={() => setDisciplinaId(String(d.id))}
              >
                {d.nome}
              </button>
            ))}
          </div>
          {!disciplinaId && (
            <span className="text-red-600 text-xs mt-2 block">
              Selecione uma disciplina
            </span>
          )}
        </div>

        {/* paciente */}
        {tipoAtendimento !== 'Solicitar' && (
          <div className="mb-6 relative" ref={inputRef}>
            <label className="block mb-1 font-medium">Paciente</label>
            <input
              className="w-full border rounded px-3 py-2"
              placeholder="Digite nome ou telefone para buscar"
              value={buscaPaciente}
              onChange={e => {
                setBuscaPaciente(e.target.value);
                setShowLista(true);
                setPacienteId('');
              }}
              onFocus={() => setShowLista(true)}
              required
            />
            {showLista && buscaPaciente && (
              <ul className="absolute z-10 bg-white border w-full rounded shadow max-h-40 overflow-y-auto">
                {pacientesFiltrados.length > 0 ? (
                  pacientesFiltrados.map(p => (
                    <li
                      key={p.id}
                      className="px-3 py-2 cursor-pointer hover:bg-blue-100"
                      onClick={() => handleSelecionarPaciente(p)}
                    >
                      {p.nome} – {p.telefone}
                    </li>
                  ))
                ) : (
                  <li className="px-3 py-2 text-gray-400">
                    Nenhum paciente encontrado
                  </li>
                )}
              </ul>
            )}
            {pacienteId && (
              <div className="mt-2 flex flex-col gap-2">
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={nomePaciente}
                  readOnly
                />
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={telefone}
                  readOnly
                />
              </div>
            )}
          </div>
        )}

        {/* data e hora */}
        <div className="mb-6 flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label className="block mb-1 font-medium">Data do Atendimento</label>
            <input
              type="date"
              className="w-full border rounded-full px-3 py-2"
              value={data}
              onChange={e => setData(e.target.value)}
              required
            />
          </div>
          <div className="flex-1">
            <label className="block mb-1 font-medium">Hora do Atendimento</label>
            <input
              type="time"
              className="w-full border rounded-full px-3 py-2"
              value={hora}
              onChange={e => setHora(e.target.value)}
              required
            />
          </div>
        </div>

        {/* aluno(s) */}
        <div className="mb-6">
          <label className="block mb-4 font-medium">
            Alunos que irão realizar o atendimento
          </label>
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <label className="block mb-1 text-sm font-semibold">Operador</label>
              <select
                required
                className="w-full border rounded px-3 py-2"
                value={operadorId}
                onChange={e => setOperadorId(e.target.value)}
              >
                <option value="">Selecione o operador</option>
                {alunos.map(a => (
                  <option key={a.id} value={a.id}>
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>
            <div className="flex-1 mt-4 md:mt-0">
              <label className="block mb-1 text-sm font-semibold">Auxiliar</label>
              <select
                className="w-full border rounded px-3 py-2"
                value={auxiliar1Id}
                onChange={e => setAuxiliar1Id(e.target.value)}
              >
                <option value="">Selecione o auxiliar</option>
                {alunos.map(a => (
                  <option key={a.id} value={a.id}>
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* botões */}
        <div className="mt-8 flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {tipoAtendimento === 'Solicitar'
              ? 'Solicitar para Recepção'
              : 'Agendar Paciente'}
          </button>
          {agendamentoEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {mensagem && (
          <p className="mt-4 text-red-600">
            {mensagem}
          </p>
        )}
      </form>
    </div>
  );
}
